from flask import Flask, request, jsonify
from collections import defaultdict, Counter
from werkzeug.security import safe_str_cmp
import os
import json
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)

# In-memory storage for simplicity
image_labels = defaultdict(list)
allowed_labels = {'cat', 'dog', 'bird'}

# Load secrets securely
def load_secret(secret_name):
    try:
        with open(f'/run/secrets/{secret_name}', 'r') as secret_file:
            return secret_file.read().strip()
    except FileNotFoundError:
        logging.error(f"Secret {secret_name} not found.")
        return None

# Securely load API token
API_TOKEN = load_secret('API_TOKEN')

# Validate input
def validate_input(data):
    if 'image_id' not in data or 'label' not in data:
        return False
    if data['label'] not in allowed_labels:
        return False
    return True

# Authenticate requests
def authenticate_request(token):
    return safe_str_cmp(token, API_TOKEN)

# Endpoint to submit labels
@app.route('/submit_label', methods=['POST'])
def submit_label():
    auth_token = request.headers.get('Authorization')
    if not authenticate_request(auth_token):
        return jsonify({'error': 'Unauthorized'}), 401

    data = request.json
    if not validate_input(data):
        return jsonify({'error': 'Invalid input'}), 400

    image_id = data['image_id']
    label = data['label']
    image_labels[image_id].append(label)
    return jsonify({'status': 'Label submitted successfully'})

# Aggregate labels using majority voting
def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in image_labels.items():
        label_count = Counter(labels)
        majority_label, _ = label_count.most_common(1)[0]
        aggregated_labels[image_id] = majority_label
    return aggregated_labels

# Endpoint to train model
@app.route('/train_model', methods=['POST'])
def train_model():
    auth_token = request.headers.get('Authorization')
    if not authenticate_request(auth_token):
        return jsonify({'error': 'Unauthorized'}), 401

    aggregated_labels = aggregate_labels()
    # Placeholder for model training logic
    # train_model_on_data(aggregated_labels)
    logging.info(f"Training model on data: {json.dumps(aggregated_labels)}")
    return jsonify({'status': 'Model training initiated'})

